import React, { useEffect, useState } from 'react';
//import Swal from 'sweetalert2';
//import './ManageOfficers.css'; // Include your custom CSS

const ManageOfficers = () => {
    const [officers, setOfficers] = useState([]);
    const [loading, setLoading] = useState(true);
    
    // Fetch officers from the backend
    useEffect(() => {
        const fetchOfficers = async () => {
            try {
                const response = await fetch('/api/officers'); // Adjust the API endpoint as needed
                const data = await response.json();
                setOfficers(data);
            } catch (error) {
                console.error('Error fetching officers:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchOfficers();
    }, []);

    const confirmDelete = (officerId) => {
        Swal.fire({
            title: 'Are you sure?',
            text: "You won't be able to revert this!",
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#3085d6',
            cancelButtonColor: '#d33',
            confirmButtonText: 'Yes, delete it!'
        }).then(async (result) => {
            if (result.isConfirmed) {
                try {
                    // Send DELETE request to the server
                    await fetch(`/api/officers/${officerId}`, { method: 'DELETE' });
    
                    // Update the state with the filtered list of officers
                    setOfficers(prevOfficers => prevOfficers.filter(officer => officer.id !== officerId));
    
                    Swal.fire('Deleted!', 'The officer has been deleted.', 'success');
                } catch (error) {
                    console.error('Error deleting officer:', error);
                    Swal.fire('Error!', 'There was an error deleting the officer.', 'error');
                }
            }
        });
    };
    

    if (loading) return <div>Loading...</div>;

    return (
        <div id="app">
            <div id="sidebar" className='active'>
                <div className="sidebar-wrapper active">
                    <div className="sidebar-header" style={{ height: '50px', marginTop: '-30px' }}>
                        <a href="admin.php">
                            <img src="./assets/images/logo.jpg" alt="Logo" />
                            <span>CDRD</span>
                        </a>
                        <button className="sidebar-toggler btn x"><i data-feather="x"></i></button>
                    </div>
                </div>
            </div>

            <div id="main">
                <nav className="navbar navbar-header navbar-expand navbar-light">
                    <div className="collapse navbar-collapse" id="navbarSupportedContent">
                        <ul className="navbar-nav d-flex align-items-center navbar-light ms-auto">
                            <li className="dropdown">
                                <a href="#" className="nav-link dropdown-toggle nav-link-lg nav-link-user">
                                    <div className="avatar me-1">
                                        <img src="assets/images/admin.png" alt="" />
                                        <div className="d-none d-md-block d-lg-inline-block">Welcome, Admin</div>
                                    </div>
                                </a>
                            </li>
                        </ul>
                    </div>
                </nav>

                <div className="main-content container-fluid">
                    <div className="page-title">
                        <div className="row">
                            <div className="col-12 col-md-6 order-md-1 order-last">
                                <h3>Manage Officers</h3>
                            </div>
                            <div className="col-12 col-md-6 order-md-2 order-first">
                                <nav aria-label="breadcrumb" className='breadcrumb-header'>
                                    <ol className="breadcrumb">
                                        <li className="breadcrumb-item active" aria-current="page">Manage Officers</li>
                                    </ol>
                                </nav>
                            </div>
                        </div>
                    </div>
                    <section className="section">
                        <div className="card">
                            <div className="card-body">
                                <table className='table' id="table1">
                                    <thead>
                                        <tr>
                                            <th>Officer Number</th>
                                            <th>Name</th>
                                            <th>Wing</th>
                                            <th>Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {officers.length > 0 ? (
                                            officers.map(officer => (
                                                <tr key={officer.id}>
                                                    <td>{officer.officer_number}</td>
                                                    <td>{officer.name}</td>
                                                    <td>{officer.wing}</td>
                                                    <td>
                                                        <div className='action-buttons' style={{ display: 'flex', gap: '10px' }}>
                                                            <a href={`/view_officer?id=${officer.id}`} className='btn btn-info'>View</a>
                                                            <a href={`/update_officer?id=${officer.id}`} className='btn btn-primary'>Update</a>
                                                            <button className='btn btn-danger' onClick={() => confirmDelete(officer.id)}>Delete</button>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))
                                        ) : (
                                            <tr>
                                                <td colSpan='4'>No records found</td>
                                            </tr>
                                        )}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </section>
                </div>
            </div>
        </div>
    );
};

export default ManageOfficers;
